// Server-side pagination via AG Grid infinite row model.
// Strategy: any significant model change (refreshKey bumped, column shape
// changed, or first paint) triggers a full grid rebuild. This is more
// reliable than purgeInfiniteCache when the viewport is empty.
// Steady-state model updates (same shape, same key) just deliver rows to
// the currently pending getRows callback.
let gridApi = null;
let pendingSuccess = null;
let lastRefreshKey = null;
let lastColumnSignature = '';
let lastResponseTs = null;
const PAGE_SIZE = 100;

function pretty(k) {
  return k.charAt(0).toUpperCase() + k.slice(1).replace(/([A-Z])/g, ' $1').replace(/__/g, ' \u00b7 ').trim();
}

function deriveColumns(model) {
  const picked = model && model.columns;
  const sample = (model && Array.isArray(model.rows) && model.rows[0]) || null;
  const fields = Array.isArray(picked) && picked.length > 0 ? picked : (sample ? Object.keys(sample) : []);
  if (fields.length === 0) return [{ headerName: 'Loading...', field: '_loading', flex: 1 }];
  return fields.map(f => ({
    headerName: pretty(f),
    field: f,
    resizable: true,
    minWidth: 120,
    valueFormatter: p => (p.value && typeof p.value === 'object') ? JSON.stringify(p.value) : p.value
  }));
}

function makeDatasource() {
  return {
    rowCount: undefined,
    getRows: function(params) {
      pendingSuccess = params.successCallback;
      if (appsmith.updateModel) {
        appsmith.updateModel({ pendingStart: params.startRow, pendingEnd: params.endRow, pendingTs: Date.now() });
      }
      appsmith.triggerEvent('onFetchPage');
    }
  };
}

function deliverRows(model) {
  if (!pendingSuccess) return;
  const rows = Array.isArray(model && model.rows) ? model.rows : [];
  const total = (model && typeof model.totalRows === 'number') ? model.totalRows : null;
  const start = (model && typeof model.pageStart === 'number') ? model.pageStart : 0;
  const lastRow = total != null
    ? total
    : (rows.length < PAGE_SIZE ? start + rows.length : -1);
  pendingSuccess(rows, lastRow);
  pendingSuccess = null;
}

function renderGrid(model) {
  const columnDefs = deriveColumns(model);
  lastColumnSignature = columnDefs.map(c => c.field).join(',');
  pendingSuccess = null;
  const gridOptions = {
    columnDefs,
    rowModelType: 'infinite',
    cacheBlockSize: PAGE_SIZE,
    maxConcurrentDatasourceRequests: 1,
    pagination: true,
    paginationPageSize: PAGE_SIZE,
    defaultColDef: { resizable: true, minWidth: 120 },
    datasource: makeDatasource(),
    animateRows: true,
    popupParent: document.body,
    onGridReady: function(params) { gridApi = params.api; }
  };
  const gridDiv = document.querySelector('#myGrid');
  if (!gridDiv) return;
  gridDiv.innerHTML = '';
  gridApi = agGrid.createGrid(gridDiv, gridOptions);
}

appsmith.onReady(function() {
  renderGrid(appsmith.model);
  lastRefreshKey = Number(appsmith.model && appsmith.model.refreshKey) || 0;
  lastResponseTs = Number(appsmith.model && appsmith.model.responseTs) || 0;

  appsmith.onModelChange(function(model) {
    const key = Number(model && model.refreshKey) || 0;
    const newCols = deriveColumns(model);
    const newSig = newCols.map(function(c) { return c.field; }).join(',');

    // Filter or report changed => rebuild grid (forces fresh getRows).
    if (key !== lastRefreshKey || newSig !== lastColumnSignature) {
      lastRefreshKey = key;
      lastColumnSignature = newSig;
      lastResponseTs = Number(model && model.responseTs) || 0;
      renderGrid(model);
      return;
    }

    // Steady-state: deliver new rows to the pending getRows callback.
    const ts = Number(model && model.responseTs) || 0;
    if (ts !== lastResponseTs) { lastResponseTs = ts; deliverRows(model); }
  });
});

